"use client";

import * as React from "react";
import "./styles/toast.css";

// ─────────────────────────────────────────────────────────────
//  TYPES
// ─────────────────────────────────────────────────────────────

export type ToastVariant = "default" | "success" | "danger" | "warning";
export type ToastPosition = 
  | "top-right" 
  | "top-left" 
  | "bottom-right" 
  | "bottom-left" 
  | "top-center" 
  | "bottom-center";

export interface ToastProps {
  id?: string;
  title?: React.ReactNode;
  description?: React.ReactNode;
  variant?: ToastVariant;
  position?: ToastPosition;
  onClose?: () => void;
  className?: string;
  children?: React.ReactNode;
}

// ─────────────────────────────────────────────────────────────
//  COMPONENTS
// ─────────────────────────────────────────────────────────────

/**
 * Toast - Individual toast message component.
 */
export const Toast = React.forwardRef<HTMLDivElement, ToastProps>(
  ({ id, title, description, variant = "default", onClose, className = "", children, ...props }, ref) => {
    const [isClosing, setIsClosing] = React.useState(false);

    const handleClose = React.useCallback(() => {
      setIsClosing(true);
      setTimeout(() => {
        onClose?.();
      }, 200); // Match CSS transition/animation time
    }, [onClose]);

    return (
      <div
        ref={ref}
        className={`toast toast--${variant} ${isClosing ? "toast--closing" : ""} ${className}`.trim()}
        role="status"
        aria-live="polite"
        {...props}
      >
        <div className="toast-content">
          {title && <h3 className="toast-title">{title}</h3>}
          {description && <div className="toast-description">{description}</div>}
          {children}
        </div>
        <button
          type="button"
          className="toast-close"
          onClick={handleClose}
          aria-label="Close"
        >
          <svg
            width="14"
            height="14"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            strokeWidth="2.5"
            strokeLinecap="round"
            strokeLinejoin="round"
          >
            <line x1="18" y1="6" x2="6" y2="18" />
            <line x1="6" y1="6" x2="18" y2="18" />
          </svg>
        </button>
      </div>
    );
  }
);

Toast.displayName = "Toast";

/**
 * ToastViewport - Container for multiple toasts.
 */
export const ToastViewport = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement> & { position?: ToastPosition }>(
  ({ className = "", position = "bottom-right", style, ...props }, ref) => {
    // Positioning map for inline styles
    const positionStyles: Record<ToastPosition, React.CSSProperties> = {
      "top-left": { top: 0, left: 0 },
      "top-right": { top: 0, right: 0 },
      "bottom-left": { bottom: 0, left: 0 },
      "bottom-right": { bottom: 0, right: 0 },
      "top-center": { top: 0, left: "50%", transform: "translateX(-50%)" },
      "bottom-center": { bottom: 0, left: "50%", transform: "translateX(-50%)" },
    };

    return (
      <div
        ref={ref}
        className={`onebi-toast-viewport onebi-toast-viewport--${position} ${className}`.trim()}
        style={{ 
          ...positionStyles[position], 
          ...style 
        }}
        {...props}
      />
    );
  }
);

ToastViewport.displayName = "ToastViewport";

/* ============================================================
   toast.css — Toast & Toaster styles
   ============================================================ */

:root {
  --toast-bg: #ffffff;
  --toast-text: #111827;
  --toast-border: #e5e7eb;
  --toast-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -2px rgba(0, 0, 0, 0.05);
  --toast-radius: 8px;

  --toast-primary: #2563eb;
  --toast-success: #16a34a;
  --toast-danger: #dc2626;
  --toast-warning: #d97706;
}

/* --- VIEWPORT POSITIONS --- */
.onebi-toast-viewport {
  position: fixed;
  z-index: 9999;
  display: flex;
  flex-direction: column;
  gap: 12px;
  width: 420px;
  max-width: 100vw;
  padding: 24px;
  pointer-events: none;
  outline: none;
  /* Temporary debug border */
  border: 1px dashed rgba(0,0,0,0.1);
}

.onebi-toast-viewport--top-right    { top: 0; right: 0; bottom: auto !important; left: auto !important; }
.onebi-toast-viewport--top-left     { top: 0; left: 0; bottom: auto !important; right: auto !important; }
.onebi-toast-viewport--bottom-right { bottom: 0; right: 0; top: auto !important; left: auto !important; }
.onebi-toast-viewport--bottom-left  { bottom: 0; left: 0; top: auto !important; right: auto !important; }

.onebi-toast-viewport--top-center {
  top: 0;
  left: 50%;
  transform: translateX(-50%);
  bottom: auto !important;
  right: auto !important;
}

.onebi-toast-viewport--bottom-center {
  bottom: 0;
  left: 50%;
  transform: translateX(-50%);
  top: auto !important;
  right: auto !important;
}

/* --- TOAST BASE --- */
.toast {
  pointer-events: auto;
  position: relative;
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 12px;
  width: 100%;
  padding: 16px;
  background: var(--toast-bg);
  border: 1px solid var(--toast-border);
  border-radius: var(--toast-radius);
  box-shadow: var(--toast-shadow);
  overflow: hidden;
  transition: all 0.2s ease-in-out;

  /* Animations */
  animation: toast-slide-in 0.3s cubic-bezier(0.16, 1, 0.3, 1);
}

.toast--closing {
  animation: toast-fade-out 0.2s ease-in forwards;
}

/* --- VARIANTS --- */
.toast--default { border-left: 4px solid var(--toast-primary); }
.toast--success { border-left: 4px solid var(--toast-success); }
.toast--danger  { border-left: 4px solid var(--toast-danger); }
.toast--warning { border-left: 4px solid var(--toast-warning); }

/* --- CONTENT --- */
.toast-content {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.toast-title {
  margin: 0;
  font-size: 14px;
  font-weight: 600;
  color: var(--toast-text);
}

.toast-description {
  margin: 0;
  font-size: 13px;
  color: #6b7280;
  line-height: 1.4;
}

/* --- CLOSE BUTTON --- */
.toast-close {
  padding: 4px;
  background: transparent;
  border: none;
  border-radius: 4px;
  color: #9ca3af;
  cursor: pointer;
  transition: color 0.2s, background 0.2s;
  display: flex;
  align-items: center;
  justify-content: center;
}

.toast-close:hover {
  background: #f3f4f6;
  color: #111827;
}

/* --- ANIMATIONS --- */
@keyframes toast-slide-in {
  from {
    transform: translateY(20px);
    opacity: 0;
  }
  to {
    transform: translateY(0);
    opacity: 1;
  }
}

/* Adjust slide-in based on position if needed, but translateY is generally safe */
.onebi-toast-viewport--top-right .toast,
.onebi-toast-viewport--top-left .toast,
.onebi-toast-viewport--top-center .toast {
  animation-name: toast-slide-down;
}

@keyframes toast-slide-down {
  from {
    transform: translateY(-20px);
    opacity: 0;
  }
  to {
    transform: translateY(0);
    opacity: 1;
  }
}

@keyframes toast-fade-out {
  from {
    opacity: 1;
    transform: scale(1);
  }
  to {
    opacity: 0;
    transform: scale(0.95);
  }
}

/* --- DARK MODE --- */
@media (prefers-color-scheme: dark) {
  :root {
    --toast-bg: #1f2937;
    --toast-text: #f9fafb;
    --toast-border: #374151;
  }

  .toast-description {
    color: #9ca3af;
  }

  .toast-close:hover {
    background: #374151;
    color: #f9fafb;
  }
}
